        return;
     }
     setIsSubmitting(true);
     const success = await placeOrder(orderType, {
        note: '',
        delivery: orderType === 'delivery' ? {
            address: deliveryAddress,
            zoneName: 'TBD',
            fee: 0 // Will be calculated by staff
