}

export interface CartItem {
  id: string;
  pizzaId: string;
  name: string;
  nameTh?: string; // Store localized name in cart
  basePrice: number;
  selectedToppings: Topping[];
  quantity: number;
  totalPrice: number;
  subItems?: SubItem[]; // New: Stores choices for combos
