  const [orderDate, setOrderDate] = useState<'today' | 'tomorrow'>(() => {
      // If store is open OR if it's closed but morning (can order for lunch)
      if (isStoreOpen || canOrderForToday()) return 'today';
      return 'tomorrow';
  });

