                            <tbody>{receiptData.items.map((item: any, i: number) => (<tr key={i} className="align-top"><td>{item.quantity}</td><td>{item.name}</td><td className="text-right">{item.totalPrice.toLocaleString()}</td></tr>))}</tbody>
