                            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                                <h3 className="text-lg font-bold mb-4 flex items-center gap-2"><ImageIcon/> Media & Links</h3>
                                <div className="mb-6"><label className="text-xs font-bold text-gray-500 uppercase block mb-2">Promo Banner</label><div className="flex gap-2 mb-2"><input type="text" className="flex-1 border rounded-lg p-2 text-sm" placeholder="https://..." value={mediaForm.promoBannerUrl} onChange={e => setMediaForm({...mediaForm, promoBannerUrl: e.target.value})} /><label className="bg-gray-200 hover:bg-gray-300 text-gray-700 px-3 py-2 rounded-lg cursor-pointer flex items-center gap-2"><Upload size={16}/> <span className="text-xs font-bold">Upload</span><input type="file" accept="image/*" className="hidden" onChange={handleBannerUpload}/></label></div>{mediaForm.promoBannerUrl && (<div className="h-32 w-full bg-gray-100 rounded-lg overflow-hidden relative"><img src={mediaForm.promoBannerUrl} className="w-full h-full object-cover opacity-80" /><div className="absolute inset-0 flex items-center justify-center font-bold text-gray-600">Preview</div></div>)}</div>
                                <div className="mb-6"><label className="text-xs font-bold text-gray-500 uppercase block mb-2">Review Video Links</label><div className="space-y-2">{[0,1,2].map(i => (<input key={i} type="text" className="w-full border rounded-lg p-2 text-sm" placeholder={`Review Link #${i+1}`} value={mediaForm.reviewLinks?.[i] || ''} onChange={e => updateLocalMediaLink('review', i, e.target.value)}/>))}</div></div>
                                <div className="mb-6"><label className="text-xs font-bold text-gray-500 uppercase block mb-2">Event Gallery</label><div className="flex flex-wrap gap-2 mb-2">{mediaForm.eventGalleryUrls?.map((url, i) => (<div key={i} className="w-20 h-20 relative group rounded-lg overflow-hidden border"><img src={url} className="w-full h-full object-cover"/><button onClick={() => { const newArr = mediaForm.eventGalleryUrls.filter((_, idx) => idx !== i); setMediaForm(prev => ({...prev, eventGalleryUrls: newArr})); }} className="absolute top-0 right-0 bg-red-500 text-white p-1 opacity-0 group-hover:opacity-100 transition"><X size={12}/></button></div>))}<label className="w-20 h-20 flex flex-col items-center justify-center border-2 border-dashed border-gray-300 rounded-lg hover:bg-gray-50 cursor-pointer text-gray-400"><Plus size={24}/><span className="text-[10px]">Add</span><input type="file" accept="image/*" className="hidden" onChange={handleEventImageUpload}/></label></div></div>
                                <button onClick={handleSaveMediaSettings} className="w-full bg-brand-600 text-white font-bold py-3 rounded-xl hover:bg-brand-700 transition">Save Media Settings</button>
                            </div>

                            {/* Contact & Payment */}
                            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                                <h3 className="text-lg font-bold mb-4 flex items-center gap-2"><Phone/> Contact & Payment</h3>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                     <div><label className="text-xs font-bold text-gray-500 uppercase block mb-1">Contact Phone</label><input type="text" className="w-full border rounded-lg p-2" value={contactForm.contactPhone} onChange={e => setContactForm({...contactForm, contactPhone: e.target.value})}/></div>
                                     <div><label className="text-xs font-bold text-gray-500 uppercase block mb-1">PromptPay Number</label><input type="text" className="w-full border rounded-lg p-2" value={contactForm.promptPayNumber} onChange={e => setContactForm({...contactForm, promptPayNumber: e.target.value})}/></div>
                                     <div><label className="text-xs font-bold text-gray-500 uppercase block mb-1">Google Maps Link</label><input type="text" className="w-full border rounded-lg p-2" value={contactForm.mapUrl} onChange={e => setContactForm({...contactForm, mapUrl: e.target.value})}/></div>
                                     <div><label className="text-xs font-bold text-gray-500 uppercase block mb-1">Facebook Link</label><input type="text" className="w-full border rounded-lg p-2" value={contactForm.facebookUrl} onChange={e => setContactForm({...contactForm, facebookUrl: e.target.value})}/></div>
                                     <div><label className="text-xs font-bold text-gray-500 uppercase block mb-1">Line Link</label><input type="text" className="w-full border rounded-lg p-2" value={contactForm.lineUrl} onChange={e => setContactForm({...contactForm, lineUrl: e.target.value})}/></div>
                                     <div><label className="text-xs font-bold text-gray-500 uppercase block mb-1">Review URL</label><input type="text" className="w-full border rounded-lg p-2" value={contactForm.reviewUrl} onChange={e => setContactForm({...contactForm, reviewUrl: e.target.value})}/></div>
                                </div>
                                <button onClick={handleSaveContactSettings} className="w-full bg-gray-900 text-white font-bold py-3 rounded-xl hover:bg-black transition">Save Contact & Payment</button>
                            </div>

                            {/* News Manager */}
                             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                                <h3 className="text-lg font-bold mb-4 flex items-center gap-2"><Newspaper/> News & Events</h3>
                                <form onSubmit={handleAddNews} className="space-y-3 mb-6"><input type="text" placeholder="Title" className="w-full border rounded-lg p-2" value={newsForm.title} onChange={e => setNewsForm({...newsForm, title: e.target.value})} required/><textarea placeholder="Summary" className="w-full border rounded-lg p-2" rows={2} value={newsForm.summary} onChange={e => setNewsForm({...newsForm, summary: e.target.value})} required/><div className="flex gap-2"><input type="text" placeholder="Image URL (Optional)" className="w-1/2 border rounded-lg p-2" value={newsForm.imageUrl} onChange={e => setNewsForm({...newsForm, imageUrl: e.target.value})} /><input type="text" placeholder="Link URL (Optional)" className="w-1/2 border rounded-lg p-2" value={newsForm.linkUrl} onChange={e => setNewsForm({...newsForm, linkUrl: e.target.value})} /></div><button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-blue-700">Add News</button></form>
                                <div className="space-y-2">{storeSettings.newsItems?.map(news => (<div key={news.id} className="flex justify-between items-center p-3 border rounded-lg bg-gray-50"><div className="text-sm font-bold">{news.title}</div><button onClick={() => deleteNewsItem(news.id)} className="text-red-500 hover:text-red-700"><Trash2 size={16}/></button></div>))}</div>
                             </div>

                            {/* Database Tools */}
                            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6"><h3 className="text-lg font-bold mb-4 flex items-center gap-2"><Database/> Data Management</h3><div className="flex flex-wrap gap-4"><button onClick={handleExportCustomers} className="bg-indigo-500 hover:bg-indigo-600 text-white px-4 py-3 rounded-lg font-bold shadow flex items-center gap-2"><User size={18}/> Export Customers</button><button onClick={seedDatabase} className="bg-yellow-500 hover:bg-yellow-600 text-white px-4 py-3 rounded-lg font-bold shadow flex items-center gap-2"><Upload size={18}/> Push Menu to Database</button></div><p className="text-xs text-gray-500 mt-2">* Push Menu overwrites database items with code constants.</p></div>
                        </div>
                    </div>
                )}

                {/* 5. QR CODE GENERATOR TAB */}
                {activeTab === 'qr_gen' && (
                    <div className="flex-1 bg-gray-100 p-6 overflow-y-auto pb-24 md:pb-6 flex items-center justify-center"><div className="bg-white rounded-2xl shadow-xl p-8 max-w-md w-full text-center"><h2 className="text-2xl font-bold mb-6 flex items-center justify-center gap-2"><QrCode/> Table QR Generator</h2><div className="mb-6"><label className="text-xs font-bold text-gray-500 uppercase block mb-2">Base URL</label><input type="text" className="w-full border-2 border-gray-200 rounded-xl p-3 text-center font-mono text-sm focus:border-brand-500 outline-none" value={qrBaseUrl} onChange={e => setQrBaseUrl(e.target.value)}/></div><div className="mb-8"><label className="text-xs font-bold text-gray-500 uppercase block mb-2">Table Number</label><div className="flex items-center justify-center gap-4"><button onClick={() => setQrTableNum(String(Math.max(1, parseInt(qrTableNum)-1)))} className="bg-gray-100 p-3 rounded-full hover:bg-gray-200"><Minus size={20}/></button><input type="number" className="w-24 text-center text-3xl font-bold border-b-2 border-brand-500 outline-none" value={qrTableNum} onChange={e => setQrTableNum(e.target.value)}/><button onClick={() => setQrTableNum(String(parseInt(qrTableNum)+1))} className="bg-gray-100 p-3 rounded-full hover:bg-gray-200"><Plus size={20}/></button></div></div><div className="bg-gray-50 p-6 rounded-2xl border-2 border-dashed border-gray-300 mb-6 flex flex-col items-center justify-center cursor-pointer hover:bg-white hover:border-brand-500 transition" onClick={() => setShowQrFullScreen(true)}><img src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(getCleanQrUrl() + '?table=' + qrTableNum)}`} className="w-48 h-48 mb-2"/><div className="text-xs text-gray-400 font-mono break-all">{getCleanQrUrl() + '?table=' + qrTableNum}</div><div className="text-xs text-brand-600 font-bold mt-2 flex items-center gap-1"><Maximize2 size={12}/> Click to Enlarge</div></div><button onClick={handlePrintQrCard} className="w-full bg-gray-900 text-white py-4 rounded-xl font-bold text-lg shadow-lg hover:bg-black flex items-center justify-center gap-2"><Printer size={20}/> Print Table Card</button></div></div>
                )}
            </main>

            {/* --- MODALS --- */}

            {selectedPizza && (
                <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
                    <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl flex flex-col max-h-[90vh] overflow-hidden">
                        <div className="bg-gray-900 text-white p-5 flex justify-between items-center shrink-0"><div><h2 className="text-2xl font-bold">{getLocalizedItem(selectedPizza).name}</h2><p className="text-gray-300 text-sm">฿{selectedPizza.basePrice}</p></div><button onClick={() => setSelectedPizza(null)} className="bg-white/20 p-2 rounded-full hover:bg-white/40"><X size={24}/></button></div>
                        <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                            <div className="mb-6 bg-white p-4 rounded-xl border border-gray-200 shadow-sm"><label className="text-sm font-bold text-gray-700 mb-2 flex items-center gap-2"><MessageCircle size={18}/> Special Instructions / Comments</label><input type="text" placeholder="e.g. No Spicy, Extra Crispy, No Olive..." className="w-full border-2 border-gray-200 rounded-xl p-3 text-lg focus:border-brand-500 outline-none" value={specialInstructions} onChange={e => setSpecialInstructions(e.target.value)}/></div>
                             {selectedPizza.category === 'pizza' && (
                                <div className="mb-6">
                                    <h3 className="font-bold text-gray-800 mb-3 flex items-center gap-2"><ChefHat size={20}/> Extras / Toppings</h3>
                                    <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                        {toppings.filter(t => t.available !== false).map(topping => {
                                            const isSelected = selectedToppings.some(t => t.id === topping.id);
                                            return (
                                                <button key={topping.id} onClick={() => toggleTopping(topping)} className={`p-2 rounded-xl border text-left transition relative flex items-center gap-3 overflow-hidden ${isSelected ? 'border-brand-500 bg-brand-50 ring-2 ring-brand-200' : 'border-gray-200 bg-white hover:bg-gray-50'}`}>
                                                    <div className="w-10 h-10 bg-gray-100 rounded-lg shrink-0 overflow-hidden">
                                                        {topping.image ? <img src={topping.image} className="w-full h-full object-cover"/> : <div className="w-full h-full flex items-center justify-center text-gray-300"><ChefHat size={16}/></div>}
                                                    </div>
                                                    <div>
                                                        <div className="font-bold text-gray-800 text-sm">{topping.name}</div>
                                                        <div className="text-xs text-gray-500">+{topping.price}</div>
                                                    </div>
                                                    {isSelected && <CheckCircle2 size={18} className="absolute top-2 right-2 text-brand-600"/>}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>
                             )}
                        </div>
                        <div className="p-6 bg-white border-t border-gray-200 shrink-0"><div className="flex items-center justify-between gap-4"><div className="flex items-center bg-gray-100 rounded-xl p-2"><button onClick={() => setQuantity(Math.max(1, quantity - 1))} className="w-12 h-12 flex items-center justify-center bg-white rounded-lg shadow-sm text-gray-600 text-xl font-bold hover:bg-gray-50"><Minus/></button><span className="w-16 text-center text-2xl font-bold">{quantity}</span><button onClick={() => setQuantity(quantity + 1)} className="w-12 h-12 flex items-center justify-center bg-white rounded-lg shadow-sm text-gray-600 text-xl font-bold hover:bg-gray-50"><Plus/></button></div><button onClick={confirmAddToCart} className="flex-1 bg-brand-600 text-white h-16 rounded-xl font-bold text-xl shadow-xl hover:bg-brand-700 flex items-center justify-center gap-2"><Plus size={24}/> Add ฿{((selectedPizza.basePrice + selectedToppings.reduce((s,t) => s+t.price, 0)) * quantity).toLocaleString()}</button></div></div>
                    </div>
                </div>
            )}

            {showQrFullScreen && (<div className="fixed inset-0 z-50 bg-white flex flex-col items-center justify-center p-8 cursor-pointer" onClick={() => setShowQrFullScreen(false)}><h1 className="text-6xl font-bold mb-4">Table {qrTableNum}</h1><img src={`https://api.qrserver.com/v1/create-qr-code/?size=500x500&data=${encodeURIComponent(getCleanQrUrl() + '?table=' + qrTableNum)}`} className="w-[80vmin] h-[80vmin] shadow-2xl border-4 border-black rounded-3xl"/><p className="mt-8 text-2xl font-bold text-gray-500 animate-pulse">Scan to Order</p></div>)}

            {showPaymentModal && (
                <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl flex overflow-hidden flex-col md:flex-row h-[80vh]">
                        <div className="md:w-1/2 bg-gray-50 border-r border-gray-200 p-6 flex flex-col"><h2 className="text-xl font-bold mb-4 flex items-center gap-2 text-gray-800"><Receipt size={24}/> {selectedOrder ? `Bill for Table ${selectedOrder.tableNumber}` : 'Current Order'}</h2><div className="flex-1 overflow-y-auto pr-2 space-y-3">{(selectedOrder ? selectedOrder.items : cart).map((item, idx) => (<div key={idx} className="flex justify-between items-start bg-white p-3 rounded-lg shadow-sm border border-gray-100"><div><div className="font-bold text-gray-800">{item.quantity}x {item.name}</div><div className="text-xs text-gray-500">{item.selectedToppings.map(t => t.name).join(', ')}{item.subItems?.map(s => `+ ${s.name}`).join(', ')}</div></div><div className="font-bold text-gray-700">฿{item.totalPrice}</div></div>))}</div><div className="mt-4 pt-4 border-t border-gray-200"><div className="flex justify-between items-center text-2xl font-bold text-gray-900"><span>Total Amount</span><span>฿{selectedOrder ? selectedOrder.totalAmount : cartTotal}</span></div></div></div>
                        <div className="md:w-1/2 p-6 flex flex-col bg-white"><div className="flex justify-between items-center mb-6"><h3 className="font-bold text-lg text-gray-500 uppercase">Payment Method</h3><button onClick={() => setShowPaymentModal(false)} className="bg-gray-100 p-2 rounded-full hover:bg-gray-200"><X size={20}/></button></div><div className="grid grid-cols-2 gap-4 mb-6"><button onClick={() => setPaymentMethod('cash')} className={`p-6 rounded-2xl border-2 flex flex-col items-center gap-3 transition ${paymentMethod === 'cash' ? 'border-brand-500 bg-brand-50 text-brand-700' : 'border-gray-100 text-gray-400 hover:border-gray-300'}`}><Banknote size={32}/><span className="font-bold text-lg">CASH</span></button><button onClick={() => setPaymentMethod('qr_transfer')} className={`p-6 rounded-2xl border-2 flex flex-col items-center gap-3 transition ${paymentMethod === 'qr_transfer' ? 'border-brand-500 bg-brand-50 text-brand-700' : 'border-gray-100 text-gray-400 hover:border-gray-300'}`}><QrCode size={32}/><span className="font-bold text-lg">SCAN QR</span></button></div><div className="flex-1 flex flex-col justify-center">{paymentMethod === 'cash' ? (<div className="space-y-4 animate-fade-in"><div><label className="text-xs font-bold text-gray-400 uppercase block mb-2">Cash Received</label><div className="relative"><span className="absolute left-4 top-1/2 -translate-y-1/2 text-2xl font-bold text-gray-400">฿</span><input type="number" autoFocus className="w-full pl-10 pr-4 py-4 text-3xl font-bold border-2 border-gray-200 rounded-xl focus:border-brand-500 outline-none" value={cashReceived} onChange={e => setCashReceived(e.target.value)} placeholder="0"/></div></div><div className="flex justify-between items-center p-4 bg-gray-50 rounded-xl border border-gray-100"><span className="font-bold text-gray-500 uppercase text-sm">Change</span><span className={`text-3xl font-bold ${change < 0 ? 'text-red-500' : 'text-green-600'}`}>฿{change >= 0 ? change.toLocaleString() : '0'}</span></div><div className="grid grid-cols-4 gap-2">{[100, 500, 1000].map(amt => (<button key={amt} onClick={() => setCashReceived(String(amt))} className="py-2 bg-gray-100 rounded-lg font-bold text-gray-600 hover:bg-gray-200">{amt}</button>))}<button onClick={() => setCashReceived(String(selectedOrder ? selectedOrder.totalAmount : cartTotal))} className="py-2 bg-brand-100 rounded-lg font-bold text-brand-600 hover:bg-brand-200">Exact</button></div></div>) : (<div className="flex flex-col items-center animate-fade-in"><div className="bg-white p-4 rounded-xl border-2 border-brand-500 shadow-lg mb-4"><img src={promptPayQRUrl} className="w-48 h-48 md:w-56 md:h-56 mix-blend-multiply" /></div><p className="text-center text-gray-500 text-sm font-bold">Scan with any Banking App</p><div className="mt-2 text-2xl font-bold text-brand-600">฿{(selectedOrder ? selectedOrder.totalAmount : cartTotal).toLocaleString()}</div></div>)}</div><div className="mt-6 flex gap-3"><button onClick={handlePrintBill} className="px-4 py-4 rounded-xl font-bold bg-gray-200 text-gray-700 hover:bg-gray-300 transition"><Printer size={24}/></button><button onClick={handleFinalizePayment} className="flex-1 bg-green-600 text-white py-4 rounded-xl font-bold text-xl shadow-lg hover:bg-green-700 transition flex items-center justify-center gap-2">{paymentMethod === 'cash' ? 'Confirm Payment' : 'Confirm Transfer'}<CheckCircle size={24}/></button></div></div>
                    </div>
                </div>
            )}

            {/* --- ADD/EDIT ITEM MODAL --- */}
            {showItemModal && (
                <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl p-6 w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
                        <h2 className="text-xl font-bold mb-4">{itemForm.id ? 'Edit Item' : 'New Item'}</h2>
                        <div className="space-y-3">
                            <input type="text" placeholder="Name (English)" className="w-full border p-2 rounded" value={itemForm.name} onChange={e => setItemForm({...itemForm, name: e.target.value})} />
                            <input type="text" placeholder="Name (Thai)" className="w-full border p-2 rounded" value={itemForm.nameTh} onChange={e => setItemForm({...itemForm, nameTh: e.target.value})} />
                            <input type="number" placeholder="Price" className="w-full border p-2 rounded" value={itemForm.basePrice} onChange={e => setItemForm({...itemForm, basePrice: parseFloat(e.target.value)})} />
                            <textarea placeholder="Description" className="w-full border p-2 rounded" value={itemForm.description} onChange={e => setItemForm({...itemForm, description: e.target.value})} />
                            <div><label className="block text-xs font-bold text-gray-500 uppercase mb-1">Category</label><select className="w-full border p-2 rounded" value={itemForm.category} onChange={e => setItemForm({...itemForm, category: e.target.value as any})}>{CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.label}</option>)}</select></div>
                            {itemForm.category === 'promotion' && (<div className="bg-orange-50 p-3 rounded-lg border border-orange-200"><label className="block text-xs font-bold text-orange-700 uppercase mb-1">Combo Settings</label><div className="flex items-center gap-2"><span className="text-sm">Number of pizzas selectable:</span><input type="number" className="w-16 border p-1 rounded text-center font-bold" value={itemForm.comboCount || 0} onChange={e => setItemForm({...itemForm, comboCount: parseInt(e.target.value)})}/></div><p className="text-xs text-orange-600 mt-1">Set to 0 if this is just a standard item, not a "Choose X items" combo.</p></div>)}
                            <div><label className="block text-xs font-bold text-gray-500 uppercase mb-1">Image Source</label><div className="flex gap-2"><input type="text" placeholder="Image URL" className="flex-1 border p-2 rounded" value={itemForm.image} onChange={e => setItemForm({...itemForm, image: e.target.value})} /><label className="bg-gray-200 px-3 py-2 rounded cursor-pointer hover:bg-gray-300 flex items-center gap-2"><Upload size={16}/> <span className="text-xs font-bold">Upload</span><input type="file" accept="image/*" className="hidden" onChange={handleImageUpload}/></label></div></div>
                            {itemForm.image && <img src={itemForm.image} className="w-full h-32 object-cover rounded-lg" />}
                            {itemForm.id && (<button onClick={() => { if(confirm('Delete this item?')) { deletePizza(itemForm.id!); setShowItemModal(false); } }} className="w-full text-red-500 text-sm font-bold py-2 border border-red-200 rounded hover:bg-red-50">Delete Item</button>)}
                            <div className="flex gap-2 pt-2"><button onClick={() => setShowItemModal(false)} className="flex-1 py-3 bg-gray-200 rounded-lg font-bold text-gray-700">Cancel</button><button onClick={handleSaveItem} className="flex-1 py-3 bg-brand-600 text-white rounded-lg font-bold hover:bg-brand-700">Save</button></div>
                        </div>
                    </div>
                </div>
            )}

            {/* --- ADD/EDIT TOPPING MODAL --- */}
            {showToppingsModal && (
                <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl p-6 w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto">
                        <h2 className="text-xl font-bold mb-4">{toppingForm.id ? 'Edit Topping' : 'New Topping'}</h2>
                        <div className="space-y-3">
                            <input type="text" placeholder="Name (English)" className="w-full border p-2 rounded" value={toppingForm.name} onChange={e => setToppingForm({...toppingForm, name: e.target.value})} />
                            <input type="text" placeholder="Name (Thai)" className="w-full border p-2 rounded" value={toppingForm.nameTh} onChange={e => setToppingForm({...toppingForm, nameTh: e.target.value})} />
                            <input type="number" placeholder="Price" className="w-full border p-2 rounded" value={toppingForm.price} onChange={e => setToppingForm({...toppingForm, price: parseFloat(e.target.value)})} />

                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Category</label>
                                <select className="w-full border p-2 rounded" value={toppingForm.category} onChange={e => setToppingForm({...toppingForm, category: e.target.value as any})}>
                                    <option value="sauce">Sauce</option>
                                    <option value="cheese">Cheese</option>
                                    <option value="meat">Meat</option>
                                    <option value="vegetable">Vegetable</option>
                                    <option value="seasoning">Seasoning</option>
                                    <option value="other">Other</option>
                                </select>
                            </div>

                            <div className="flex items-center gap-3 bg-gray-50 p-2 rounded-lg border">
                                <label className="text-sm font-bold text-gray-700">Available (In Stock)</label>
                                <button onClick={() => setToppingForm({...toppingForm, available: !toppingForm.available})} className={`w-12 h-6 rounded-full relative transition ${toppingForm.available ? 'bg-green-500' : 'bg-gray-300'}`}>
                                    <div className={`w-4 h-4 bg-white rounded-full absolute top-1 transition-all ${toppingForm.available ? 'left-7' : 'left-1'}`}></div>
                                </button>
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Image Source</label>
                                <div className="flex gap-2">
                                    <input type="text" placeholder="Image URL" className="flex-1 border p-2 rounded" value={toppingForm.image} onChange={e => setToppingForm({...toppingForm, image: e.target.value})} />
                                    <label className="bg-gray-200 px-3 py-2 rounded cursor-pointer hover:bg-gray-300 flex items-center gap-2">
                                        <Upload size={16}/> <span className="text-xs font-bold">Upload</span>
                                        <input type="file" accept="image/*" className="hidden" onChange={handleToppingImageUpload}/>
                                    </label>
                                </div>
                            </div>

                            {toppingForm.image && <img src={toppingForm.image} className="w-full h-32 object-cover rounded-lg" />}

                            {toppingForm.id && (
                                <button onClick={() => { if(confirm('Delete this topping?')) { deleteTopping(toppingForm.id!); setShowToppingsModal(false); } }} className="w-full text-red-500 text-sm font-bold py-2 border border-red-200 rounded hover:bg-red-50">Delete Topping</button>
                            )}

                            <div className="flex gap-2 pt-2">
                                <button onClick={() => setShowToppingsModal(false)} className="flex-1 py-3 bg-gray-200 rounded-lg font-bold text-gray-700">Cancel</button>
                                <button onClick={handleSaveTopping} className="flex-1 py-3 bg-brand-600 text-white rounded-lg font-bold hover:bg-brand-700">Save</button>
                            </div>
                        </div>
                    </div>
                </div>
            )}

        </div>
    );
};

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { 
  Pizza, Topping, CartItem, Order, OrderType, OrderSource, OrderStatus, 
  PaymentMethod, CustomerProfile, Expense, StoreSettings, NewsItem, 
  SavedFavorite, Language, AppView, ProductCategory, SubItem, ExpenseCategory
} from '../types';
import { 
  INITIAL_MENU, INITIAL_TOPPINGS, DEFAULT_STORE_SETTINGS, 
  OPERATING_HOURS, GP_RATES, TRANSLATIONS, CATEGORIES 
} from '../constants';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';

interface StoreContextType {
  language: Language;
  toggleLanguage: () => void;
  t: (key: keyof typeof TRANSLATIONS.en, params?: Record<string, string | number>) => string;
  getLocalizedItem: (item: { name: string; nameTh?: string; description?: string; descriptionTh?: string } | undefined) => { name: string; description: string };

  currentView: AppView;
  navigateTo: (view: AppView) => void;

  isAdminLoggedIn: boolean;
  adminLogin: (u: string, p: string) => boolean;
  adminLogout: () => void;

  shopLogo: string;
  updateShopLogo: (base64: string) => void;

  menu: Pizza[];
  addPizza: (pizza: Pizza) => Promise<void>;
  updatePizza: (pizza: Pizza) => Promise<void>;
  deletePizza: (id: string) => Promise<void>;
  updatePizzaPrice: (id: string, newPrice: number) => Promise<void>;
  togglePizzaAvailability: (id: string) => Promise<void>;
  toggleBestSeller: (id: string) => Promise<void>;
  generateLuckyPizza: () => { pizza: Pizza; toppings: Topping[] } | null;
  seedDatabase: () => Promise<void>;

  toppings: Topping[];
  addTopping: (topping: Topping) => Promise<void>;
  updateTopping: (topping: Topping) => Promise<void>;
  deleteTopping: (id: string) => Promise<void>;

  cart: CartItem[];
  addToCart: (item: CartItem) => void;
  removeFromCart: (itemId: string) => void;
  updateCartItemQuantity: (itemId: string, delta: number) => void;
  updateCartItem: (item: CartItem) => void;
  clearCart: () => void;
  cartTotal: number;

  customer: CustomerProfile | null;
  setCustomer: (profile: CustomerProfile) => Promise<void>;
  registerCustomer: (profile: CustomerProfile) => Promise<'created' | 'updated'>;
  customerLogin: (phone: string, pass: string) => Promise<boolean>;
  getAllCustomers: () => Promise<any[]>;
  addToFavorites: (name: string, pizzaId: string, toppings: Topping[]) => Promise<void>;
  claimReward: () => boolean;

  orders: Order[];
  placeOrder: (
    type: OrderType, 
    details?: {
      note?: string;
      delivery?: { address: string; zoneName: string; fee: number };
      paymentMethod?: PaymentMethod;
      pickupTime?: string;
      tableNumber?: string;
      source?: OrderSource;
      status?: OrderStatus;
    }
  ) => Promise<boolean>;
  updateOrderStatus: (orderId: string, status: OrderStatus) => Promise<void>;
  completeOrder: (orderId: string, paymentDetails: { paymentMethod: PaymentMethod, note?: string }) => Promise<void>;
  deleteOrder: (orderId: string) => Promise<void>;
  reorderItem: (orderId: string) => void;
  fetchOrders: () => Promise<void>;

  expenses: Expense[];
  addExpense: (expense: Expense) => Promise<void>;
  deleteExpense: (id: string) => Promise<void>;

  isStoreOpen: boolean;
  isHoliday: boolean;
  closedMessage: string;
  storeSettings: StoreSettings;
  toggleStoreStatus: (isOpen: boolean, message?: string) => Promise<void>;
  updateStoreSettings: (settings: Partial<StoreSettings>) => Promise<void>;
  generateTimeSlots: (dateOffset?: number) => string[];
  canOrderForToday: () => boolean;

  addNewsItem: (item: NewsItem) => Promise<void>;
  deleteNewsItem: (id: string) => Promise<void>;

  tableSession: string | null;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // --- Language State ---
  const [language, setLanguage] = useState<Language>(() => {
      return (localStorage.getItem('damac_lang') as Language) || 'en';
  });
  const toggleLanguage = () => {
      setLanguage(prev => {
          const newLang = prev === 'en' ? 'th' : 'en';
          localStorage.setItem('damac_lang', newLang);
          return newLang;
      });
  };
  const t = (key: keyof typeof TRANSLATIONS.en, params?: Record<string, string | number>) => {
      let text = TRANSLATIONS[language][key] || TRANSLATIONS['en'][key] || key;
      if (params) {
          Object.entries(params).forEach(([k, v]) => {
              text = text.replace(`{${k}}`, String(v));
          });
      }
      return text;
  };
  const getLocalizedItem = (item: { name: string; nameTh?: string; description?: string; descriptionTh?: string } | undefined) => {
      if (!item) return { name: '', description: '' };
      return {
          name: (language === 'th' && item.nameTh) ? item.nameTh : item.name,
          description: (language === 'th' && item.descriptionTh) ? item.descriptionTh : (item.description || '')
      };
  };

  // --- View Navigation & Table Session ---
  // Initialize from URL params so direct links work
  const [currentView, setCurrentView] = useState<AppView>(() => {
    if (typeof window !== 'undefined') {
      const params = new URLSearchParams(window.location.search);
      const view = params.get('view');
      return (view === 'kitchen' || view === 'pos') ? view : 'customer';
    }
    return 'customer';
  });

  // Check for Table Param (QR Code Scan)
  const [tableSession, setTableSession] = useState<string | null>(() => {
      if (typeof window !== 'undefined') {
          const params = new URLSearchParams(window.location.search);
          return params.get('table');
      }
      return null;
  });

  useEffect(() => {
    const handlePopState = () => {
      const params = new URLSearchParams(window.location.search);
      const view = params.get('view');
      const table = params.get('table');
      setCurrentView((view === 'kitchen' || view === 'pos') ? view : 'customer');
      if (table) setTableSession(table);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigateTo = (view: AppView) => {
    setCurrentView(view);
    if (typeof window !== 'undefined') {
        const url = new URL(window.location.href);
        if (view === 'customer') {
            url.searchParams.delete('view');
        } else {
            url.searchParams.set('view', view);
        }
        // Preserve table param if it exists
        if (tableSession) {
            url.searchParams.set('table', tableSession);
        }
        window.history.pushState({}, '', url.toString());
        window.scrollTo(0, 0);
    }
  };

  // --- Auth State ---
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(() => sessionStorage.getItem('damac_auth') === 'true');
  const adminLogin = (u: string, p: string) => {
    if ((u === 'oat299@gmail.com' && p === 'PizzaDamac2025*') || (u === 'admin' && p === '123')) {
        setIsAdminLoggedIn(true);
        sessionStorage.setItem('damac_auth', 'true');
        return true;
    }
    return false;
  };
  const adminLogout = () => {
    setIsAdminLoggedIn(false);
    sessionStorage.removeItem('damac_auth');
    navigateTo('customer');
  };

  // --- Branding ---
  const [shopLogo, setShopLogo] = useState(() => localStorage.getItem('damac_logo') || '');
  const updateShopLogo = (base64: string) => {
    setShopLogo(base64);
    localStorage.setItem('damac_logo', base64);
  };

  // --- Data States (From DB + Local Storage Backup) ---
  const [menu, setMenu] = useState<Pizza[]>(() => {
      if (typeof window !== 'undefined') {
          const saved = localStorage.getItem('damac_menu');
          if (saved) {
              try { return JSON.parse(saved); } catch(e) {}
          }
      }
      return INITIAL_MENU;
  });

  // Persist Menu to LocalStorage
  useEffect(() => {
      localStorage.setItem('damac_menu', JSON.stringify(menu));
  }, [menu]);

  const [toppings, setToppings] = useState<Topping[]>(INITIAL_TOPPINGS);
  const [orders, setOrders] = useState<Order[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [customer, setCustState] = useState<CustomerProfile | null>(() => {
    const saved = localStorage.getItem('damac_customer');
    return saved ? JSON.parse(saved) : null;
  });

  // --- Store Settings State (From DB + Local Storage Backup) ---
  const [storeSettings, setStoreSettings] = useState<StoreSettings>(() => {
      if (typeof window !== 'undefined') {
          const saved = localStorage.getItem('damac_store_settings');
          if (saved) {
              try { return { ...DEFAULT_STORE_SETTINGS, ...JSON.parse(saved) }; } 
              catch(e) { console.error("Settings parse error", e); }
          }
      }
      return DEFAULT_STORE_SETTINGS;
  });

  // Persist Settings to LocalStorage
  useEffect(() => {
      localStorage.setItem('damac_store_settings', JSON.stringify(storeSettings));
  }, [storeSettings]);

  const [isHoliday, setIsHoliday] = useState(false);
  const [isStoreOpen, setIsStoreOpen] = useState(true);

  // Helper to check if today is within holiday range
  const checkHolidayStatus = (start?: string, end?: string) => {
      if (!start || !end) return false;
      const today = new Date().toISOString().split('T')[0];
      return today >= start && today <= end;
  };

  const checkOperatingHours = () => {
    const now = new Date();
    const currentHour = now.getHours() + now.getMinutes() / 60;
    const isOpenHours = currentHour >= OPERATING_HOURS.open && currentHour < OPERATING_HOURS.close;
    return isOpenHours;
  };

  const canOrderForToday = () => {
      const now = new Date();
      const currentHour = now.getHours() + now.getMinutes() / 60;
      // Can order today if we haven't passed the closing time yet
      return currentHour < OPERATING_HOURS.close;
  };

  useEffect(() => {
     // Check if explicit holiday in DB OR manually closed
     const isScheduledHoliday = checkHolidayStatus(storeSettings.holidayStart, storeSettings.holidayEnd);
     const effectiveHoliday = isScheduledHoliday || !storeSettings.isOpen;

     // Store is "Open" if no holiday/manual close AND within hours
     const withinHours = checkOperatingHours();

     setIsHoliday(isScheduledHoliday);
     // Note: isStoreOpen tracks "Currently accepting ASAP orders". 
     // If closed (morning), you can still preorder for today.
     setIsStoreOpen(!effectiveHoliday && withinHours);
  }, [storeSettings]);

  // DB Sync
  const fetchMenu = async () => {
      if (!isSupabaseConfigured) return;
      try {
        const { data, error } = await supabase.from('menu_items').select('*');
        if (!error && data) {
           // Merge with local to ensure category/combo logic exists even if DB column missing
           const mergedMenu = data.map(d => {
               const local = INITIAL_MENU.find(m => m.id === d.id);
               return {
                   ...d, 
                   basePrice: d.base_price, 
                   nameTh: d.name_th, 
                   descriptionTh: d.description_th, 
                   isBestSeller: d.is_best_seller,
                   comboCount: d.combo_count !== undefined ? d.combo_count : (local?.comboCount || 0),
                   category: d.category || local?.category || 'pizza'
               };
           });
           setMenu(mergedMenu);
        }
      } catch (err) { console.error("Menu fetch failed", err); }
  };
  const fetchToppings = async () => {
      if (!isSupabaseConfigured) return;
      try {
          const { data, error } = await supabase.from('toppings').select('*');
          if (!error && data) {
              const mergedToppings = data.map(d => {
                  const local = INITIAL_TOPPINGS.find(t => t.id === d.id);
                  return {
                      ...d, 
                      nameTh: d.name_th,
                      category: d.category || local?.category || 'other',
                      image: d.image || undefined,
                      available: d.available !== false // Default true if null/undefined
                  };
              });
              setToppings(mergedToppings);
          }
      } catch (err) { console.error("Toppings fetch failed", err); }
  };
  const fetchOrders = async () => {
      if (!isSupabaseConfigured) return;
      try {
          const { data, error } = await supabase.from('orders').select('*').order('created_at', { ascending: false });
          if (error) {
              if (error.code === '42P01') {
                  console.warn("Table 'orders' missing. Please run SQL script.");
                  return;
              }
          }
          if (data) setOrders(data.map(d => ({
              ...d, 
              customerName: d.customer_name, 
              customerPhone: d.customer_phone, 
              totalAmount: d.total_amount,
              netAmount: d.net_amount || d.total_amount,
              createdAt: d.created_at,
              deliveryAddress: d.delivery_address,
              deliveryZone: d.delivery_zone,
              deliveryFee: d.delivery_fee,
              paymentMethod: d.payment_method,
              pickupTime: d.pickup_time,
              tableNumber: d.table_number
          })));
      } catch (err) { console.error("Orders fetch failed", err); }
  };
  const fetchSettings = async () => {
      if (!isSupabaseConfigured) return;
      try {
          const { data } = await supabase.from('store_settings').select('*').single();
          if (data) {
              setStoreSettings({
                  isOpen: data.is_open,
                  closedMessage: data.closed_message,
                  promoBannerUrl: data.promo_banner_url,
                  promoContentType: data.promo_content_type,
                  holidayStart: data.holiday_start,
                  holidayEnd: data.holiday_end,
                  // New fields with fallback to constants
                  reviewUrl: data.review_url || DEFAULT_STORE_SETTINGS.reviewUrl,
                  facebookUrl: data.facebook_url || DEFAULT_STORE_SETTINGS.facebookUrl,
                  lineUrl: data.line_url || DEFAULT_STORE_SETTINGS.lineUrl,
                  mapUrl: data.map_url || DEFAULT_STORE_SETTINGS.mapUrl,
                  contactPhone: data.contact_phone || DEFAULT_STORE_SETTINGS.contactPhone,
                  // JSON or Array columns
                  reviewLinks: data.review_links || [],
                  vibeLinks: data.vibe_links || [],
                  eventGalleryUrls: data.event_gallery_urls || DEFAULT_STORE_SETTINGS.eventGalleryUrls, // Map new column
                  newsItems: data.news_items || []
              });
          }
      } catch (err) { console.error("Settings fetch failed", err); }
  };
  const fetchCustomerProfile = async () => {
      if (!isSupabaseConfigured || !customer) return;
      try {
          // Fetch latest profile including addresses
          const { data } = await supabase.from('customers').select('*').eq('phone', customer.phone).single();
          if (data) {
              const updatedProfile: CustomerProfile = {
                  name: data.name,
                  phone: data.phone,
                  password: data.password,
                  address: data.address,
                  birthday: data.birthday,
                  loyaltyPoints: data.loyalty_points,
                  tier: data.tier,
                  savedFavorites: data.saved_favorites || [],
                  orderHistory: data.order_history || [],
                  pdpaAccepted: data.pdpa_accepted,
                  savedAddresses: data.saved_addresses || []
              };
              setCustState(updatedProfile);
              localStorage.setItem('damac_customer', JSON.stringify(updatedProfile));
          }
      } catch (err) { console.error("Profile fetch failed", err); }
  }

  useEffect(() => {
    if (isSupabaseConfigured) {
        fetchMenu();
        fetchToppings();
        fetchOrders();
        fetchSettings();

        const subscription = supabase.channel('realtime_updates')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, (payload) => {
            fetchOrders(); // Reload orders when change happens
        })
        .on('postgres_changes', { event: '*', schema: 'public', table: 'menu_items' }, fetchMenu)
        .on('postgres_changes', { event: '*', schema: 'public', table: 'toppings' }, fetchToppings) // Subscribe to toppings
        .on('postgres_changes', { event: '*', schema: 'public', table: 'store_settings' }, fetchSettings)
        .subscribe();

        // Polling fallback every 5 seconds to ensure status updates even if realtime is flaky
        const interval = setInterval(() => {
             fetchOrders();
        }, 5000);

        return () => { 
            subscription.unsubscribe(); 
            clearInterval(interval);
        }
    }
  }, []);

  // Update customer profile on load if logged in
  useEffect(() => {
      if (isSupabaseConfigured && customer) {
          fetchCustomerProfile();
      }
  }, []);

  // Actions
  const addPizza = async (pizza: Pizza) => {
      if (isSupabaseConfigured) {
          try {
            await supabase.from('menu_items').insert([{
                id: pizza.id, name: pizza.name, name_th: pizza.nameTh, 
                description: pizza.description, description_th: pizza.descriptionTh,
                base_price: pizza.basePrice, image: pizza.image, available: pizza.available, category: pizza.category,
                combo_count: pizza.comboCount
            }]);
          } catch (e) { console.error(e); }
      } 
      // Always update local state for immediate feedback
      setMenu(prev => [...prev, pizza]);
  };
  const updatePizza = async (pizza: Pizza) => {
      if (isSupabaseConfigured) {
          try {
            await supabase.from('menu_items').update({
                name: pizza.name, name_th: pizza.nameTh, 
                description: pizza.description, description_th: pizza.descriptionTh,
                base_price: pizza.basePrice, image: pizza.image, available: pizza.available, category: pizza.category,
                combo_count: pizza.comboCount
            }).eq('id', pizza.id);
          } catch(e) { console.error(e); }
      }
      // Always update local
      setMenu(prev => prev.map(p => p.id === pizza.id ? pizza : p));
  };
  const deletePizza = async (id: string) => {
      if (isSupabaseConfigured) {
          try { await supabase.from('menu_items').delete().eq('id', id); } catch(e) { console.error(e); }
      }
      setMenu(prev => prev.filter(p => p.id !== id));
  };
  const updatePizzaPrice = async (id: string, newPrice: number) => {
      const p = menu.find(i => i.id === id);
      if (p) await updatePizza({ ...p, basePrice: newPrice });
  };
  const togglePizzaAvailability = async (id: string) => {
      const p = menu.find(i => i.id === id);
      if (p) await updatePizza({ ...p, available: !p.available });
  };
  const toggleBestSeller = async (id: string) => {
      const p = menu.find(i => i.id === id);
      if (p) {
          const newVal = !p.isBestSeller;
          if (isSupabaseConfigured) {
              try {
                await supabase.from('menu_items').update({ is_best_seller: newVal }).eq('id', id);
              } catch(e) { console.error(e); }
          }
          setMenu(prev => prev.map(item => item.id === id ? {...item, isBestSeller: newVal} : item));
      }
  }

  const generateLuckyPizza = () => {
      const pizzaBase = menu.find(p => p.name.includes("Create Your Own"));
      if (!pizzaBase) return null;

      const randomToppings: Topping[] = [];
      const numToppings = Math.floor(Math.random() * 3) + 2; // 2-4 toppings
      const shuffled = [...toppings].sort(() => 0.5 - Math.random());

      for(let i=0; i<numToppings; i++) {
          if (shuffled[i]) randomToppings.push(shuffled[i]);
      }
      return { pizza: pizzaBase, toppings: randomToppings };
  };

  const seedDatabase = async () => {
      if (!isSupabaseConfigured) {
          alert("Database not connected. Cannot upload.");
          return;
      }
      const confirmUpload = window.confirm("This will upload all the latest Menu Items and Toppings from the code to the Database. It will overwrite existing items with the same ID. Continue?");
      if (!confirmUpload) return;

      try {
          // Upload Menu
          for (const p of INITIAL_MENU) {
              const { error } = await supabase.from('menu_items').upsert({
                  id: p.id, name: p.name, name_th: p.nameTh, 
                  base_price: p.basePrice, description: p.description, 
                  description_th: p.descriptionTh, image: p.image, 
                  category: p.category, available: p.available, 
                  is_best_seller: p.isBestSeller, combo_count: p.comboCount
              });
              if (error) console.error("Menu Seed Error", error);
          }
          // Upload Toppings
          for (const t of INITIAL_TOPPINGS) {
              const { error } = await supabase.from('toppings').upsert({
                  id: t.id, name: t.name, name_th: t.nameTh, price: t.price,
                  category: t.category, image: t.image, available: t.available
              });
              if (error) console.error("Topping Seed Error", error);
          }
          alert("Menu uploaded to database successfully! Your app is now in sync.");
          fetchMenu(); // Refresh
          fetchToppings(); // Refresh
      } catch (err) {
          console.error("Seeding failed", err);
          alert("Seeding failed. Check console for details.");
      }
  };

  const addTopping = async (topping: Topping) => {
      if (isSupabaseConfigured) {
          try {
            await supabase.from('toppings').insert([{
                id: topping.id, name: topping.name, name_th: topping.nameTh, price: topping.price, 
                category: topping.category, image: topping.image, available: topping.available
            }]);
          } catch(e) { console.error(e); }
      }
      setToppings(prev => [...prev, topping]);
  };

  const updateTopping = async (topping: Topping) => {
      if (isSupabaseConfigured) {
          try {
            await supabase.from('toppings').update({
                name: topping.name, name_th: topping.nameTh, price: topping.price, 
                category: topping.category, image: topping.image, available: topping.available
            }).eq('id', topping.id);
          } catch(e) { console.error(e); }
      }
      setToppings(prev => prev.map(t => t.id === topping.id ? topping : t));
  };

  const deleteTopping = async (id: string) => {
      if (isSupabaseConfigured) {
          try { await supabase.from('toppings').delete().eq('id', id); } catch(e) { console.error(e); }
      }
      setToppings(prev => prev.filter(t => t.id !== id));
  };

  // Cart
  const addToCart = (item: CartItem) => setCart(prev => [...prev, item]);
  const updateCartItemQuantity = (itemId: string, delta: number) => {
      setCart(prev => prev.map(item => {
          if (item.id === itemId) {
              const newQty = Math.max(1, item.quantity + delta);
              return { ...item, quantity: newQty, totalPrice: (item.totalPrice / item.quantity) * newQty };
          }
          return item;
      }));
  };
  const updateCartItem = (updatedItem: CartItem) => {
      setCart(prev => prev.map(item => item.id === updatedItem.id ? updatedItem : item));
  };
  const removeFromCart = (itemId: string) => setCart(prev => prev.filter(item => item.id !== itemId));
  const clearCart = () => setCart([]);
  const cartTotal = cart.reduce((sum, item) => sum + item.totalPrice, 0);

  // Customer
  const setCustomer = async (profile: CustomerProfile) => {
      setCustState(profile);
      localStorage.setItem('damac_customer', JSON.stringify(profile));

      // Update Offline Backup
      const saved = localStorage.getItem('damac_mock_customers');
      let list = saved ? JSON.parse(saved) : [];
      list = list.filter((c: any) => c.phone !== profile.phone);
      list.push(profile);
      localStorage.setItem('damac_mock_customers', JSON.stringify(list));

      // Sync to DB if connected
      if (isSupabaseConfigured) {
          try {
            const payload: any = {
                phone: profile.phone, 
                name: profile.name, 
                address: profile.address, 
                birthday: profile.birthday, 
                password: profile.password,
                loyalty_points: profile.loyaltyPoints, 
                tier: profile.tier,
                saved_favorites: profile.savedFavorites, 
                order_history: profile.orderHistory
            };

            if (profile.pdpaAccepted !== undefined) payload.pdpa_accepted = profile.pdpaAccepted;
            if (profile.savedAddresses !== undefined) payload.saved_addresses = profile.savedAddresses;

            await supabase.from('customers').upsert(payload);
          } catch(e) { console.error("Customer sync failed", e); }
      }
  };

  // Smart Register / Reset Password
  const registerCustomer = async (newProfile: CustomerProfile): Promise<'created' | 'updated'> => {
      let existingPoints = 0;
      let existingHistory: string[] = [];
      let existingFavorites: SavedFavorite[] = [];
      let existingTier: 'Bronze' | 'Silver' | 'Gold' | undefined = undefined;
      let existingSavedAddresses: string[] = [];
      let action: 'created' | 'updated' = 'created';

      if (isSupabaseConfigured) {
          // Check if user exists
          try {
              const { data } = await supabase.from('customers').select('*').eq('phone', newProfile.phone).single();
              if (data) {
                  existingPoints = data.loyalty_points;
                  existingHistory = data.order_history || [];
                  existingFavorites = data.saved_favorites || [];
                  existingTier = data.tier;
                  existingSavedAddresses = data.saved_addresses || [];
                  action = 'updated';
              }
          } catch(e) {}
      } else {
           // Local Storage fallback for mock
           const saved = localStorage.getItem('damac_mock_customers');
           if (saved) {
               const list = JSON.parse(saved);
               const found = list.find((c: any) => c.phone === newProfile.phone);
               if (found) {
                   existingPoints = found.loyaltyPoints;
                   existingHistory = found.orderHistory;
                   existingFavorites = found.savedFavorites;
                   existingTier = found.tier;
                   existingSavedAddresses = found.savedAddresses;
                   action = 'updated';
               }
           }
      }

      const finalProfile: CustomerProfile = {
          ...newProfile,
          loyaltyPoints: existingPoints,
          orderHistory: existingHistory,
          savedFavorites: existingFavorites,
          tier: existingTier,
          savedAddresses: existingSavedAddresses.length > 0 ? existingSavedAddresses : (newProfile.address ? [newProfile.address] : [])
      };

      await setCustomer(finalProfile);
      return action;
  };

  const customerLogin = async (phone: string, pass: string): Promise<boolean> => {
      // First try DB if connected
      if (isSupabaseConfigured) {
          const { data } = await supabase.from('customers').select('*').eq('phone', phone).single();
          if (data && data.password === pass) {
              const profile: CustomerProfile = {
                  name: data.name,
                  phone: data.phone,
                  password: data.password,
                  address: data.address,
                  birthday: data.birthday,
                  loyaltyPoints: data.loyalty_points,
                  tier: data.tier,
                  savedFavorites: data.saved_favorites || [],
                  orderHistory: data.order_history || [],
                  pdpaAccepted: data.pdpa_accepted,
                  savedAddresses: data.saved_addresses || []
              };
              setCustState(profile);
              localStorage.setItem('damac_customer', JSON.stringify(profile));
              return true;
          }
      } 

      // Fallback to local mock data (for testing or offline)
      const saved = localStorage.getItem('damac_mock_customers');
      if (saved) {
           const list = JSON.parse(saved);
           const found = list.find((c: any) => c.phone === phone && c.password === pass);
           if (found) {
               setCustState(found);
               localStorage.setItem('damac_customer', JSON.stringify(found));
               return true;
           }
      }
      return false;
  };

  const getAllCustomers = async () => {
      let dbCustomers = [];
      let localCustomers = [];

      if (isSupabaseConfigured) {
          const { data } = await supabase.from('customers').select('*');
          if (data) dbCustomers = data;
      }

      // Merge with offline data
      const saved = localStorage.getItem('damac_mock_customers');
      if (saved) {
          localCustomers = JSON.parse(saved);
      }

      // Combine arrays, removing duplicates based on phone
      const combined = [...dbCustomers];
      for (const local of localCustomers) {
          if (!combined.find(c => c.phone === local.phone)) {
              combined.push(local);
          }
      }

      return combined;
  }

  const addToFavorites = async (name: string, pizzaId: string, toppings: Topping[]) => {
      if (!customer) return;
      const newFav: SavedFavorite = { id: Date.now().toString(), name, pizzaId, toppings };
      const updatedFavs = [...customer.savedFavorites, newFav];
      const updatedCustomer = { ...customer, savedFavorites: updatedFavs };
      await setCustomer(updatedCustomer);
  };

  const claimReward = () => {
      if (!customer || customer.loyaltyPoints < 10) return false;
      const updatedCustomer = { ...customer, loyaltyPoints: customer.loyaltyPoints - 10 };
      setCustomer(updatedCustomer);
      return true;
  };

  // Orders
  const placeOrder = async (
    type: OrderType, 
    details?: {
      note?: string;
      delivery?: { address: string; zoneName: string; fee: number };
      paymentMethod?: PaymentMethod;
      pickupTime?: string;
      tableNumber?: string;
      source?: OrderSource;
      status?: OrderStatus;
    }
  ) => {
      // Calculate Total
      const subtotal = cart.reduce((sum, item) => sum + item.totalPrice, 0);
      const deliveryFee = details?.delivery?.fee || 0;
      const totalAmount = subtotal + deliveryFee;

      // Calculate Net (GP Deduction)
      const source = details?.source || 'store';
      const gpRate = GP_RATES[source] || 0;
      const netAmount = totalAmount * (1 - gpRate);

      const newOrder: Order = {
          id: Date.now().toString(),
          customerName: customer ? customer.name : (details?.tableNumber ? `Table ${details.tableNumber}` : 'Guest'),
          customerPhone: customer ? customer.phone : '',
          type,
          source: source,
          status: details?.status || 'pending',
          items: [...cart],
          totalAmount,
          netAmount,
          createdAt: new Date().toISOString(),
          note: details?.note,
          deliveryAddress: details?.delivery?.address,
          deliveryZone: details?.delivery?.zoneName,
          deliveryFee: details?.delivery?.fee,
          paymentMethod: details?.paymentMethod,
          pickupTime: details?.pickupTime,
          tableNumber: details?.tableNumber
      };

      if (isSupabaseConfigured) {
          try {
             const payload: any = {
                 id: newOrder.id,
                 customer_name: newOrder.customerName,
                 customer_phone: newOrder.customerPhone,
                 type: newOrder.type,
                 source: newOrder.source,
                 status: newOrder.status,
                 items: newOrder.items,
                 total_amount: newOrder.totalAmount,
                 net_amount: newOrder.netAmount,
                 created_at: newOrder.createdAt,
                 note: newOrder.note,
                 delivery_address: newOrder.deliveryAddress,
                 delivery_zone: newOrder.deliveryZone,
                 delivery_fee: newOrder.deliveryFee,
                 payment_method: newOrder.paymentMethod,
                 pickup_time: newOrder.pickupTime,
                 table_number: newOrder.tableNumber
             };
             await supabase.from('orders').insert([payload]);
          } catch(e) { console.error("Order placement failed", e); return false; }
      }

      setOrders(prev => [newOrder, ...prev]);

      // Save ID for Guest Tracking
      localStorage.setItem('damac_last_order', newOrder.id);

      // Update Customer (Loyalty + History + Saved Address)
      if (customer) {
          // Loyalty: 1 point per pizza item
          const pizzaCount = cart.filter(i => {
               const itemDef = menu.find(m => m.id === i.pizzaId);
               return itemDef?.category === 'pizza' || itemDef?.category === 'promotion';
          }).reduce((sum, i) => sum + i.quantity, 0);

          let newPoints = customer.loyaltyPoints + pizzaCount;
          const newHistory = [newOrder.id, ...customer.orderHistory];

          let newSavedAddresses = customer.savedAddresses || [];
          if (type === 'delivery' && details?.delivery?.address) {
              if (!newSavedAddresses.includes(details.delivery.address)) {
                  newSavedAddresses = [details.delivery.address, ...newSavedAddresses].slice(0, 5); // Keep last 5
              }
          }

          const updatedCustomer = { 
              ...customer, 
              loyaltyPoints: newPoints, 
              orderHistory: newHistory,
              savedAddresses: newSavedAddresses
          };
          await setCustomer(updatedCustomer);
      }

      // Clear Cart if online/delivery or if specifically requested (Store orders might keep cart for next? No, clear it)
      clearCart();
      return true;
  };

  const updateOrderStatus = async (orderId: string, status: OrderStatus) => {
      if (isSupabaseConfigured) {
          await supabase.from('orders').update({ status }).eq('id', orderId);
      }
      setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
  };

  const completeOrder = async (orderId: string, paymentDetails: { paymentMethod: PaymentMethod, note?: string }) => {
      if (isSupabaseConfigured) {
          await supabase.from('orders').update({ 
              status: 'completed', 
              payment_method: paymentDetails.paymentMethod,
              note: paymentDetails.note // Append or overwrite? Overwrite for now or handle logic
          }).eq('id', orderId);
      }
      setOrders(prev => prev.map(o => o.id === orderId ? { 
          ...o, 
          status: 'completed', 
          paymentMethod: paymentDetails.paymentMethod,
          note: paymentDetails.note ? (o.note ? o.note + '. ' + paymentDetails.note : paymentDetails.note) : o.note
      } : o));
  };

  const deleteOrder = async (orderId: string) => {
      if (isSupabaseConfigured) {
          await supabase.from('orders').delete().eq('id', orderId);
      }
      setOrders(prev => prev.filter(o => o.id !== orderId));
  };

  const reorderItem = (orderId: string) => {
      const order = orders.find(o => o.id === orderId);
      if (order) {
          order.items.forEach(item => {
               addToCart({ ...item, id: Date.now() + Math.random().toString() });
          });
      }
  };

  // Expenses
  const addExpense = async (expense: Expense) => {
      if (isSupabaseConfigured) {
          // Assuming 'expenses' table exists
          await supabase.from('expenses').insert([{
              id: expense.id, description: expense.description, amount: expense.amount, 
              category: expense.category, date: expense.date, note: expense.note
          }]);
      }
      setExpenses(prev => [...prev, expense]);
  };
  const deleteExpense = async (id: string) => {
      if (isSupabaseConfigured) {
           await supabase.from('expenses').delete().eq('id', id);
      }
      setExpenses(prev => prev.filter(e => e.id !== id));
  };

  // Store Settings
  const toggleStoreStatus = async (isOpen: boolean, message?: string) => {
      const updates: any = { is_open: isOpen };
      if (message !== undefined) updates.closed_message = message;

      if (isSupabaseConfigured) {
          await supabase.from('store_settings').update(updates).eq('id', 1); // Assuming single row ID 1
      }
      setStoreSettings(prev => ({ ...prev, isOpen, closedMessage: message || prev.closedMessage }));
  };

  const updateStoreSettings = async (settings: Partial<StoreSettings>) => {
      if (isSupabaseConfigured) {
          // Map camelCase to snake_case for DB
          const payload: any = {};
          if (settings.promoBannerUrl !== undefined) payload.promo_banner_url = settings.promoBannerUrl;
          if (settings.promoContentType !== undefined) payload.promo_content_type = settings.promoContentType;
          if (settings.reviewLinks !== undefined) payload.review_links = settings.reviewLinks;
          if (settings.vibeLinks !== undefined) payload.vibe_links = settings.vibeLinks;
          if (settings.eventGalleryUrls !== undefined) payload.event_gallery_urls = settings.eventGalleryUrls;
          if (settings.holidayStart !== undefined) payload.holiday_start = settings.holidayStart;
          if (settings.holidayEnd !== undefined) payload.holiday_end = settings.holidayEnd;
          if (settings.reviewUrl !== undefined) payload.review_url = settings.reviewUrl;
          if (settings.facebookUrl !== undefined) payload.facebook_url = settings.facebookUrl;
          if (settings.lineUrl !== undefined) payload.line_url = settings.lineUrl;
          if (settings.mapUrl !== undefined) payload.map_url = settings.mapUrl;
          if (settings.contactPhone !== undefined) payload.contact_phone = settings.contactPhone;
          if (settings.promptPayNumber !== undefined) payload.prompt_pay_number = settings.promptPayNumber; // Assuming DB column name

          if (Object.keys(payload).length > 0) {
             const { error } = await supabase.from('store_settings').update(payload).eq('id', 1);
             if (error) {
                 await supabase.from('store_settings').insert([{ id: 1, ...payload }]);
             }
          }
      }
      setStoreSettings(prev => ({ ...prev, ...settings }));
  };

  const generateTimeSlots = (dateOffset: number = 0) => {
      const slots: string[] = [];
      const startHour = OPERATING_HOURS.open;
      const endHour = OPERATING_HOURS.close;
      const now = new Date();

      // If today, start from current time + 30 mins
      let current = startHour;

      // Loop in 30 min increments
      while (current < endHour) {
          const hour = Math.floor(current);
          const minute = (current % 1) * 60;

          if (dateOffset === 0) {
              // For Today: Filter past times
              const slotTime = new Date();
              slotTime.setHours(hour, minute, 0, 0);
              const bufferTime = new Date(now.getTime() + 30 * 60000); // +30 mins prep time

              if (slotTime > bufferTime) {
                  slots.push(`${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`);
              }
          } else {
              // Future dates
              slots.push(`${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`);
          }
          current += 0.5;
      }
      return slots;
  };

  const addNewsItem = async (item: NewsItem) => {
       const updatedNews = [item, ...(storeSettings.newsItems || [])];
       if (isSupabaseConfigured) {
           await supabase.from('store_settings').update({ news_items: updatedNews }).eq('id', 1);
       }
       setStoreSettings(prev => ({ ...prev, newsItems: updatedNews }));
  };

  const deleteNewsItem = async (id: string) => {
      const updatedNews = (storeSettings.newsItems || []).filter(n => n.id !== id);
      if (isSupabaseConfigured) {
          await supabase.from('store_settings').update({ news_items: updatedNews }).eq('id', 1);
      }
      setStoreSettings(prev => ({ ...prev, newsItems: updatedNews }));
  };

  const value = {
      language, toggleLanguage, t, getLocalizedItem,
      currentView, navigateTo,
      isAdminLoggedIn, adminLogin, adminLogout,
      shopLogo, updateShopLogo,
      menu, addPizza, updatePizza, deletePizza, updatePizzaPrice, togglePizzaAvailability, toggleBestSeller, generateLuckyPizza, seedDatabase,
      toppings, addTopping, updateTopping, deleteTopping,
      cart, addToCart, removeFromCart, updateCartItemQuantity, updateCartItem, clearCart, cartTotal,
      customer, setCustomer, registerCustomer, customerLogin, getAllCustomers, addToFavorites, claimReward,
      orders, placeOrder, updateOrderStatus, completeOrder, deleteOrder, reorderItem, fetchOrders,
      expenses, addExpense, deleteExpense,
      isStoreOpen, isHoliday, closedMessage: storeSettings.closedMessage, storeSettings, toggleStoreStatus, updateStoreSettings, generateTimeSlots, canOrderForToday,
      addNewsItem, deleteNewsItem,
      tableSession
  };

  return (
    <StoreContext.Provider value={value}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (context === undefined) {
    throw new Error('useStore must be used within a StoreProvider');
  }
  return context;
};

