    const myOrders = orders.filter(o => o.customerPhone === customer.phone);
    const uniqueItems = new Map<string, Pizza>();

    // Sort orders descending
    myOrders.sort((a,b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

