                const original = menu.find(m => m.id === item.pizzaId);
                if (original) {
                   uniqueItems.set(item.pizzaId, original);
                }
            }
            if (uniqueItems.size >= 5) break;
        }
        if (uniqueItems.size >= 5) break;
