                        <div className="flex justify-between items-center mb-4 text-xl font-bold text-gray-900">
                            <span>Total</span>
                            <span>฿{cartTotal}</span>
                        </div>
                        <button 
                            onClick={handlePlaceOrderClick}
                            disabled={cart.length === 0 || isSubmitting}
                            className="w-full bg-brand-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg hover:bg-brand-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition"
                        >
                            {isSubmitting ? 'Processing...' : t('placeOrder')}
                            {!isSubmitting && <ArrowRight size={20}/>}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* --- AUTH MODAL --- */}
        {showAuthModal && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
                <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
                     <div className="relative h-32 bg-brand-600 flex items-center justify-center shrink-0">
                         <div className="absolute inset-0 bg-black/20"></div>
                         <h2 className="relative text-white font-bold text-3xl">{authMode === 'login' ? 'Welcome Back' : 'Join Us'}</h2>
                         <button onClick={() => setShowAuthModal(false)} className="absolute top-4 right-4 text-white/80 hover:text-white"><X size={24}/></button>
                     </div>

                     <div className="p-6 flex-1 overflow-y-auto">
                         {authMode === 'login' ? (
                             <form onSubmit={handleLogin} className="space-y-4">
                                 <div>
                                     <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Phone Number</label>
                                     <div className="relative">
                                         <Phone className="absolute left-3 top-3 text-gray-400" size={18}/>
                                         <input type="tel" required className="w-full pl-10 p-3 border rounded-xl bg-gray-50 focus:bg-white transition" placeholder="0812345678" value={loginPhone} onChange={e => setLoginPhone(e.target.value)}/>
                                     </div>
                                 </div>
                                 <div>
                                     <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Password</label>
                                     <div className="relative">
                                         <Lock className="absolute left-3 top-3 text-gray-400" size={18}/>
                                         <input type="password" required className="w-full pl-10 p-3 border rounded-xl bg-gray-50 focus:bg-white transition" placeholder="••••••" value={loginPassword} onChange={e => setLoginPassword(e.target.value)}/>
                                     </div>
                                 </div>
                                 <button type="submit" className="w-full bg-gray-900 text-white py-3 rounded-xl font-bold hover:bg-black shadow-lg mt-2">Login</button>
                                 <p className="text-center text-sm text-gray-500 mt-4">
                                     New here? <button type="button" onClick={() => setAuthMode('register')} className="text-brand-600 font-bold hover:underline">Create Account</button>
                                 </p>
                             </form>
                         ) : (
                             <form onSubmit={handleRegister} className="space-y-4">
                                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Name</label>
                                        <input type="text" required className="w-full p-3 border rounded-xl bg-gray-50" placeholder="John Doe" value={regName} onChange={e => setRegName(e.target.value)}/>
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Phone</label>
                                        <input type="tel" required className="w-full p-3 border rounded-xl bg-gray-50" placeholder="081..." value={regPhone} onChange={e => setRegPhone(e.target.value)}/>
                                    </div>
                                 </div>
                                 <div>
                                     <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Create Password</label>
                                     <input type="password" required className="w-full p-3 border rounded-xl bg-gray-50" placeholder="••••••" value={regPassword} onChange={e => setRegPassword(e.target.value)}/>
                                 </div>
                                 <div>
                                     <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Birthday (Optional)</label>
                                     <input type="date" className="w-full p-3 border rounded-xl bg-gray-50" value={regBirthday} onChange={e => setRegBirthday(e.target.value)}/>
                                 </div>
                                 <div className="flex items-start gap-3 p-3 bg-gray-50 rounded-xl">
                                     <input type="checkbox" required id="pdpa" className="mt-1" checked={regPdpa} onChange={e => setRegPdpa(e.target.checked)}/>
                                     <label htmlFor="pdpa" className="text-xs text-gray-600 cursor-pointer">{t('pdpaLabel')}</label>
                                 </div>
                                 <button type="submit" className="w-full bg-brand-600 text-white py-3 rounded-xl font-bold hover:bg-brand-700 shadow-lg mt-2">Register & Reset Password</button>
                                 <p className="text-center text-sm text-gray-500 mt-4">
                                     Already have an account? <button type="button" onClick={() => setAuthMode('login')} className="text-brand-600 font-bold hover:underline">Login</button>
                                 </p>
                             </form>
                         )}
                     </div>
                </div>
            </div>
        )}

        {/* PROFILE MODAL */}
        {showProfile && customer && (
             <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
                 <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl overflow-hidden relative max-h-[90vh] flex flex-col">
                     <div className="bg-gray-900 p-6 text-white text-center relative shrink-0">
                         <button onClick={() => setShowProfile(false)} className="absolute top-4 right-4 text-white/60 hover:text-white"><X size={24}/></button>
                         <div className="w-20 h-20 bg-brand-500 rounded-full flex items-center justify-center text-3xl font-bold mx-auto mb-3 shadow-lg border-4 border-gray-800">
                             {customer.name.charAt(0)}
                         </div>
                         <h2 className="text-2xl font-bold">{customer.name}</h2>
                         <p className="text-brand-300 font-medium">{customer.loyaltyPoints} Points</p>
                     </div>

                     <div className="p-6 flex-1 overflow-y-auto bg-gray-50">
                         {/* Points Progress */}
                         <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 mb-6">
                             <div className="flex justify-between items-center mb-2">
                                 <span className="font-bold text-gray-700 text-sm">Reward Progress</span>
                                 <span className="text-xs font-bold text-brand-600">{customer.loyaltyPoints} / 10</span>
                             </div>
                             <div className="w-full bg-gray-100 h-3 rounded-full overflow-hidden mb-3">
                                 <div className="bg-brand-500 h-full transition-all" style={{ width: `${Math.min(100, (customer.loyaltyPoints / 10) * 100)}%` }}></div>
                             </div>
                             {customer.loyaltyPoints >= 10 ? (
                                 <button onClick={() => { claimReward(); setShowProfile(false); setIsCartOpen(true); }} className="w-full py-2 bg-gradient-to-r from-yellow-400 to-orange-500 text-white font-bold rounded-lg shadow-md animate-pulse">
                                     {t('claimReward')}
                                 </button>
                             ) : (
                                 <p className="text-xs text-center text-gray-500">{10 - customer.loyaltyPoints} more points {t('toFreePizza')}</p>
                             )}
                         </div>

                         {/* ACTIVE ORDER CARD */}
                         {activeOrder && (
                             <div className="bg-white p-4 rounded-xl shadow-md border-l-4 border-brand-500 mb-6 relative overflow-hidden group cursor-pointer" onClick={() => { setShowProfile(false); setShowTracker(true); }}>
                                 <div className="flex justify-between items-start mb-3 relative z-10">
                                     <div>
                                         <h3 className="font-bold text-gray-800 flex items-center gap-2">
                                             <Activity size={18} className="text-brand-600 animate-pulse"/> 
                                             Active Order
                                         </h3>
                                         <span className="text-xs text-gray-500">#{activeOrder.id.slice(-4)} • {activeOrder.items.length} items</span>
                                     </div>
                                     <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${getStatusColor(activeOrder.status)}`}>
                                         {t(activeOrder.status as any)}
                                     </span>
                                 </div>

                                 <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden mb-3 relative z-10">
                                     <div className={`h-full transition-all duration-1000 ${
                                         activeOrder.status === 'pending' ? 'w-1/6 bg-yellow-400' :
                                         activeOrder.status === 'confirmed' ? 'w-2/6 bg-blue-500' :
                                         activeOrder.status === 'acknowledged' ? 'w-3/6 bg-indigo-500' :
                                         activeOrder.status === 'cooking' ? 'w-4/6 bg-orange-500' :
                                         activeOrder.status === 'ready' ? 'w-5/6 bg-green-500' :
                                         'w-full bg-green-600'
                                     }`}></div>
                                 </div>

                                 <div className="text-center text-xs font-bold text-brand-600 flex items-center justify-center gap-1">
                                     Tap to Track <ArrowRight size={12}/>
                                 </div>
                             </div>
                         )}

                         {/* Favorites */}
                         <div className="mb-6">
                             <h3 className="font-bold text-gray-800 mb-3 flex items-center gap-2"><Heart size={16} className="text-red-500"/> {t('savedFavorites')}</h3>
                             <div className="space-y-3">
                                 {customer.savedFavorites && customer.savedFavorites.length > 0 ? (
                                     customer.savedFavorites.map(fav => (
                                         <div key={fav.id} className="bg-white p-3 rounded-xl border border-gray-200 shadow-sm flex justify-between items-center">
                                             <div>
                                                 <div className="font-bold text-sm">{fav.name}</div>
                                                 <div className="text-xs text-gray-500 line-clamp-1">{fav.toppings.map(t => t.name).join(', ')}</div>
                                             </div>
                                             <button 
                                                onClick={() => handleOrderFavorite(fav)}
                                                className="bg-brand-100 text-brand-600 p-2 rounded-full hover:bg-brand-200"
                                                title="Add to Cart"
                                             >
                                                <Plus size={16}/>
                                             </button>
                                         </div>
                                     ))
                                 ) : <p className="text-xs text-gray-400 text-center py-4 bg-white rounded-xl border border-dashed">No favorites yet</p>}
                             </div>
                         </div>

                         {/* Order History */}
                         <div>
                             <h3 className="font-bold text-gray-800 mb-3 flex items-center gap-2"><History size={16}/> {t('recentOrders')}</h3>
                             <div className="space-y-3">
                                 {orders.filter(o => o.customerPhone === customer.phone).slice(0, 5).map(order => (
                                     <div key={order.id} className="bg-white p-3 rounded-xl border border-gray-200 shadow-sm">
                                         <div className="flex justify-between items-center mb-2">
                                              <span className="text-xs font-bold text-gray-500">{new Date(order.createdAt).toLocaleDateString()}</span>
                                              <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase ${getStatusColor(order.status)}`}>{order.status}</span>
                                         </div>
                                         <div className="flex justify-between items-center">
                                              <div>
                                                  {order.items.map((item, idx) => (
                                                      <div key={idx} className="text-sm font-bold text-gray-800">{item.name} <span className="text-gray-400 font-normal">x{item.quantity}</span></div>
                                                  ))}
                                              </div>
                                              <div className="text-right">
                                                  <div className="font-bold text-gray-900">฿{order.totalAmount}</div>
                                                  <button onClick={() => { reorderItem(order.id); setShowProfile(false); setIsCartOpen(true); }} className="text-xs text-brand-600 font-bold hover:underline mt-1">{t('reorder')}</button>
                                              </div>
                                         </div>
                                     </div>
                                 ))}
                             </div>
                         </div>
                     </div>

                     <div className="p-4 bg-white border-t">
                         <button onClick={() => { setCustomer(null as any); localStorage.removeItem('damac_customer'); setShowProfile(false); }} className="w-full py-3 border border-gray-300 rounded-xl font-bold text-gray-600 hover:bg-gray-50">Log Out</button>
                     </div>
                 </div>
             </div>
        )}

    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { 
  Pizza, Topping, CartItem, Order, OrderType, OrderSource, OrderStatus, 
  PaymentMethod, CustomerProfile, Expense, StoreSettings, NewsItem, 
  SavedFavorite, Language, AppView, ProductCategory, SubItem, ExpenseCategory
} from '../types';
import { 
  INITIAL_MENU, INITIAL_TOPPINGS, DEFAULT_STORE_SETTINGS, 
  OPERATING_HOURS, GP_RATES, TRANSLATIONS, CATEGORIES 
} from '../constants';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';

interface StoreContextType {
  language: Language;
  toggleLanguage: () => void;
  t: (key: keyof typeof TRANSLATIONS.en, params?: Record<string, string | number>) => string;
  getLocalizedItem: (item: { name: string; nameTh?: string; description?: string; descriptionTh?: string } | undefined) => { name: string; description: string };

  currentView: AppView;
  navigateTo: (view: AppView) => void;

  isAdminLoggedIn: boolean;
  adminLogin: (u: string, p: string) => boolean;
  adminLogout: () => void;

  shopLogo: string;
  updateShopLogo: (base64: string) => void;

  menu: Pizza[];
  addPizza: (pizza: Pizza) => Promise<void>;
  updatePizza: (pizza: Pizza) => Promise<void>;
  deletePizza: (id: string) => Promise<void>;
  updatePizzaPrice: (id: string, newPrice: number) => Promise<void>;
  togglePizzaAvailability: (id: string) => Promise<void>;
  toggleBestSeller: (id: string) => Promise<void>;
  generateLuckyPizza: () => { pizza: Pizza; toppings: Topping[] } | null;
  seedDatabase: () => Promise<void>;

  toppings: Topping[];
  addTopping: (topping: Topping) => Promise<void>;
  updateTopping: (topping: Topping) => Promise<void>;
  deleteTopping: (id: string) => Promise<void>;

  cart: CartItem[];
  addToCart: (item: CartItem) => void;
  removeFromCart: (itemId: string) => void;
  updateCartItemQuantity: (itemId: string, delta: number) => void;
  updateCartItem: (item: CartItem) => void;
  clearCart: () => void;
  cartTotal: number;

  customer: CustomerProfile | null;
  setCustomer: (profile: CustomerProfile) => Promise<void>;
  registerCustomer: (profile: CustomerProfile) => Promise<'created' | 'updated'>;
  customerLogin: (phone: string, pass: string) => Promise<boolean>;
  getAllCustomers: () => Promise<any[]>;
  addToFavorites: (name: string, pizzaId: string, toppings: Topping[]) => Promise<void>;
  claimReward: () => boolean;

  orders: Order[];
  placeOrder: (
    type: OrderType, 
    details?: {
      note?: string;
      delivery?: { address: string; zoneName: string; fee: number };
      paymentMethod?: PaymentMethod;
      pickupTime?: string;
      tableNumber?: string;
      source?: OrderSource;
      status?: OrderStatus;
    }
  ) => Promise<boolean>;
  updateOrderStatus: (orderId: string, status: OrderStatus) => Promise<void>;
  completeOrder: (orderId: string, paymentDetails: { paymentMethod: PaymentMethod, note?: string }) => Promise<void>;
  deleteOrder: (orderId: string) => Promise<void>;
  reorderItem: (orderId: string) => void;
  fetchOrders: () => Promise<void>;

  expenses: Expense[];
  addExpense: (expense: Expense) => Promise<void>;
  deleteExpense: (id: string) => Promise<void>;

  isStoreOpen: boolean;
  isHoliday: boolean;
  closedMessage: string;
  storeSettings: StoreSettings;
  toggleStoreStatus: (isOpen: boolean, message?: string) => Promise<void>;
  updateStoreSettings: (settings: Partial<StoreSettings>) => Promise<void>;
  generateTimeSlots: (dateOffset?: number) => string[];
  canOrderForToday: () => boolean;

  addNewsItem: (item: NewsItem) => Promise<void>;
  deleteNewsItem: (id: string) => Promise<void>;

  tableSession: string | null;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // --- Language State ---
  const [language, setLanguage] = useState<Language>(() => {
      return (localStorage.getItem('damac_lang') as Language) || 'en';
  });
  const toggleLanguage = () => {
      setLanguage(prev => {
          const newLang = prev === 'en' ? 'th' : 'en';
          try {
            localStorage.setItem('damac_lang', newLang);
          } catch(e) { console.error("Storage Error", e); }
          return newLang;
      });
  };
  const t = (key: keyof typeof TRANSLATIONS.en, params?: Record<string, string | number>) => {
      let text = TRANSLATIONS[language][key] || TRANSLATIONS['en'][key] || key;
      if (params) {
          Object.entries(params).forEach(([k, v]) => {
              text = text.replace(`{${k}}`, String(v));
          });
      }
      return text;
  };
  const getLocalizedItem = (item: { name: string; nameTh?: string; description?: string; descriptionTh?: string } | undefined) => {
      if (!item) return { name: '', description: '' };
      return {
          name: (language === 'th' && item.nameTh) ? item.nameTh : item.name,
          description: (language === 'th' && item.descriptionTh) ? item.descriptionTh : (item.description || '')
      };
  };

  // --- View Navigation & Table Session ---
  // Initialize from URL params so direct links work
  const [currentView, setCurrentView] = useState<AppView>(() => {
    if (typeof window !== 'undefined') {
      const params = new URLSearchParams(window.location.search);
      const view = params.get('view');
      return (view === 'kitchen' || view === 'pos') ? view : 'customer';
    }
    return 'customer';
  });

  // Check for Table Param (QR Code Scan)
  const [tableSession, setTableSession] = useState<string | null>(() => {
      if (typeof window !== 'undefined') {
          const params = new URLSearchParams(window.location.search);
          return params.get('table');
      }
      return null;
  });

  useEffect(() => {
    const handlePopState = () => {
      const params = new URLSearchParams(window.location.search);
      const view = params.get('view');
      const table = params.get('table');
      setCurrentView((view === 'kitchen' || view === 'pos') ? view : 'customer');
      if (table) setTableSession(table);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigateTo = (view: AppView) => {
    setCurrentView(view);
    if (typeof window !== 'undefined') {
        const url = new URL(window.location.href);
        if (view === 'customer') {
            url.searchParams.delete('view');
        } else {
            url.searchParams.set('view', view);
        }
        // Preserve table param if it exists
        if (tableSession) {
            url.searchParams.set('table', tableSession);
        }
        window.history.pushState({}, '', url.toString());
        window.scrollTo(0, 0);
    }
  };

  // --- Auth State ---
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(() => sessionStorage.getItem('damac_auth') === 'true');
  const adminLogin = (u: string, p: string) => {
    if ((u === 'oat299@gmail.com' && p === 'PizzaDamac2025*') || (u === 'admin' && p === '123')) {
        setIsAdminLoggedIn(true);
        sessionStorage.setItem('damac_auth', 'true');
        return true;
    }
    return false;
  };
  const adminLogout = () => {
    setIsAdminLoggedIn(false);
    sessionStorage.removeItem('damac_auth');
    navigateTo('customer');
  };

  // --- Branding ---
  const [shopLogo, setShopLogo] = useState(() => localStorage.getItem('damac_logo') || '');
  const updateShopLogo = (base64: string) => {
    setShopLogo(base64);
    try {
        localStorage.setItem('damac_logo', base64);
    } catch(e) {
        console.warn("Storage Full: Logo could not be saved locally. It will persist in DB if connected.", e);
    }
  };

  // --- Data States (From DB + Local Storage Backup) ---
  const [menu, setMenu] = useState<Pizza[]>(() => {
      if (typeof window !== 'undefined') {
          const saved = localStorage.getItem('damac_menu');
          if (saved) {
              try { return JSON.parse(saved); } catch(e) {}
          }
      }
      return INITIAL_MENU;
  });

  // Persist Menu to LocalStorage
  useEffect(() => {
      try {
        localStorage.setItem('damac_menu', JSON.stringify(menu));
      } catch(e) { console.warn("Menu Storage Full", e); }
  }, [menu]);

  // Initialized Toppings from LocalStorage
  const [toppings, setToppings] = useState<Topping[]>(() => {
      if (typeof window !== 'undefined') {
          const saved = localStorage.getItem('damac_toppings');
          if (saved) {
              try { return JSON.parse(saved); } catch(e) {}
          }
      }
      return INITIAL_TOPPINGS;
  });

  // Persist Toppings to LocalStorage
  useEffect(() => {
      try {
        localStorage.setItem('damac_toppings', JSON.stringify(toppings));
      } catch(e) { console.warn("Toppings Storage Full", e); }
  }, [toppings]);

  const [orders, setOrders] = useState<Order[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [customer, setCustState] = useState<CustomerProfile | null>(() => {
    const saved = localStorage.getItem('damac_customer');
    return saved ? JSON.parse(saved) : null;
  });

  // --- Store Settings State (From DB + Local Storage Backup) ---
  const [storeSettings, setStoreSettings] = useState<StoreSettings>(() => {
      if (typeof window !== 'undefined') {
          const saved = localStorage.getItem('damac_store_settings');
          if (saved) {
              try { return { ...DEFAULT_STORE_SETTINGS, ...JSON.parse(saved) }; } 
              catch(e) { console.error("Settings parse error", e); }
          }
      }
      return DEFAULT_STORE_SETTINGS;
  });

  // Persist Settings to LocalStorage
  useEffect(() => {
      try {
        localStorage.setItem('damac_store_settings', JSON.stringify(storeSettings));
      } catch(e) { console.warn("Settings Storage Full", e); }
  }, [storeSettings]);

  const [isHoliday, setIsHoliday] = useState(false);
  const [isStoreOpen, setIsStoreOpen] = useState(true);

  // Helper to check if today is within holiday range
  const checkHolidayStatus = (start?: string, end?: string) => {
      if (!start || !end) return false;
      const today = new Date().toISOString().split('T')[0];
      return today >= start && today <= end;
  };

  const checkOperatingHours = () => {
    const now = new Date();
    const currentHour = now.getHours() + now.getMinutes() / 60;
    const isOpenHours = currentHour >= OPERATING_HOURS.open && currentHour < OPERATING_HOURS.close;
    return isOpenHours;
  };

  const canOrderForToday = () => {
      const now = new Date();
      const currentHour = now.getHours() + now.getMinutes() / 60;
      // Can order today if we haven't passed the closing time yet
      return currentHour < OPERATING_HOURS.close;
  };

  useEffect(() => {
     // Check if explicit holiday in DB OR manually closed
     const isScheduledHoliday = checkHolidayStatus(storeSettings.holidayStart, storeSettings.holidayEnd);
     const effectiveHoliday = isScheduledHoliday || !storeSettings.isOpen;

     // Store is "Open" if no holiday/manual close AND within hours
     const withinHours = checkOperatingHours();

     setIsHoliday(isScheduledHoliday);
     // Note: isStoreOpen tracks "Currently accepting ASAP orders". 
     // If closed (morning), you can still preorder for today.
     setIsStoreOpen(!effectiveHoliday && withinHours);
  }, [storeSettings]);

  // DB Sync
  const fetchMenu = async () => {
      if (!isSupabaseConfigured) return;
      try {
        const { data, error } = await supabase.from('menu_items').select('*');
        if (!error && data) {
           // PRESERVE LOCAL IMAGES: If DB image is missing but we have it locally, keep local.
           let localMenu: Pizza[] = [];
           try {
               const saved = localStorage.getItem('damac_menu');
               if (saved) localMenu = JSON.parse(saved);
           } catch(e) {}

           const mergedMenu = data.map(d => {
               const local = INITIAL_MENU.find(m => m.id === d.id);
               const savedLocal = localMenu.find(m => m.id === d.id);
               return {
                   ...d, 
                   basePrice: d.base_price, 
                   nameTh: d.name_th, 
                   descriptionTh: d.description_th, 
                   // Prioritize DB image, fall back to Local saved image, then Default
                   image: d.image || savedLocal?.image || local?.image || 'https://via.placeholder.com/150',
                   isBestSeller: d.is_best_seller,
                   comboCount: d.combo_count !== undefined ? d.combo_count : (local?.comboCount || 0),
                   category: d.category || local?.category || 'pizza',
                   available: d.available
               };
           });
           setMenu(mergedMenu);
        }
      } catch (err) { console.error("Menu fetch failed", err); }
  };

